import{_ as e,o as d,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Systems Technologies — Quick Summary","description":"","frontmatter":{},"headers":[],"relativePath":"quick-study/systems-summary.md","filePath":"quick-study/systems-summary.md"}'),s={name:"quick-study/systems-summary.md"};function n(o,t,i,l,c,h){return d(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="systems-technologies-—-quick-summary" tabindex="-1">Systems Technologies — Quick Summary <a class="header-anchor" href="#systems-technologies-—-quick-summary" aria-label="Permalink to &quot;Systems Technologies — Quick Summary&quot;">​</a></h1><p>Fast-scan reference for hardware, software, performance, and types of computers. No prose.</p><hr><h2 id="computer-model" tabindex="-1">Computer Model <a class="header-anchor" href="#computer-model" aria-label="Permalink to &quot;Computer Model&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Role</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Input</strong></td><td>Feed data into system</td><td>Keyboard, mouse, scanner, microphone</td></tr><tr><td><strong>Processing</strong></td><td>CPU executes instructions</td><td>CPU, ALU, CU, registers</td></tr><tr><td><strong>Memory</strong></td><td>Temporary storage during processing</td><td>RAM, ROM, cache</td></tr><tr><td><strong>Storage</strong></td><td>Permanent data storage</td><td>HDD, SSD, USB, optical disc</td></tr><tr><td><strong>Output</strong></td><td>Deliver results to user</td><td>Monitor, printer, speakers</td></tr><tr><td><strong>Communication</strong></td><td>Connect to other devices/networks</td><td>NIC, router, modem</td></tr></tbody></table><hr><h2 id="cpu-internals" tabindex="-1">CPU Internals <a class="header-anchor" href="#cpu-internals" aria-label="Permalink to &quot;CPU Internals&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Part</th><th>Function</th></tr></thead><tbody><tr><td><strong>ALU</strong></td><td>Arithmetic and Logic Unit — calculations and comparisons</td></tr><tr><td><strong>CU</strong></td><td>Control Unit — coordinates all CPU operations</td></tr><tr><td><strong>Registers</strong></td><td>Tiny fastest storage inside CPU (PC, IR, MAR, MDR, AC)</td></tr><tr><td><strong>Cache (L1/L2/L3)</strong></td><td>Ultra-fast RAM buffer on/near CPU</td></tr></tbody></table><p><strong>Fetch-Decode-Execute cycle:</strong></p><ol><li>Fetch instruction from RAM (using PC register)</li><li>Decode the instruction (CU)</li><li>Execute it (ALU or memory operation)</li><li>Store result; increment PC; repeat</li></ol><hr><h2 id="memory-comparison" tabindex="-1">Memory Comparison <a class="header-anchor" href="#memory-comparison" aria-label="Permalink to &quot;Memory Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Memory</th><th>Type</th><th>Volatile?</th><th>Speed</th><th>Size</th></tr></thead><tbody><tr><td>CPU Registers</td><td>SRAM</td><td>Yes</td><td>Fastest</td><td>Bytes</td></tr><tr><td>L1 Cache</td><td>SRAM</td><td>Yes</td><td>Very fast</td><td>KB</td></tr><tr><td>L2 Cache</td><td>SRAM</td><td>Yes</td><td>Fast</td><td>KB–MB</td></tr><tr><td>L3 Cache</td><td>SRAM</td><td>Yes</td><td>Fast</td><td>MB</td></tr><tr><td>RAM</td><td>DRAM</td><td>Yes</td><td>Moderate</td><td>GB</td></tr><tr><td>ROM (BIOS)</td><td>Non-volatile ROM</td><td>No</td><td>Moderate</td><td>MB</td></tr><tr><td>SSD</td><td>Flash</td><td>No</td><td>Moderate-fast</td><td>GB–TB</td></tr><tr><td>HDD</td><td>Magnetic</td><td>No</td><td>Slow</td><td>GB–TB</td></tr></tbody></table><hr><h2 id="cpu-performance-factors" tabindex="-1">CPU Performance Factors <a class="header-anchor" href="#cpu-performance-factors" aria-label="Permalink to &quot;CPU Performance Factors&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Factor</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Clock speed (GHz)</strong></td><td>More cycles per second = faster processing</td></tr><tr><td><strong>Number of cores</strong></td><td>More cores = more parallel tasks</td></tr><tr><td><strong>Cache size</strong></td><td>More cache = fewer slow RAM accesses</td></tr><tr><td><strong>CPU generation</strong></td><td>Newer = better architecture, efficiency</td></tr><tr><td><strong>Hyperthreading</strong></td><td>Each core handles 2 threads simultaneously</td></tr></tbody></table><hr><h2 id="gpu-performance-factors" tabindex="-1">GPU Performance Factors <a class="header-anchor" href="#gpu-performance-factors" aria-label="Permalink to &quot;GPU Performance Factors&quot;">​</a></h2><ul><li>Clock speed (GHz)</li><li>VRAM amount (GB)</li><li>Memory bus width</li><li>Model/generation (RTX 4090 vs GTX 1650)</li></ul><hr><h2 id="ram-performance-factors" tabindex="-1">RAM Performance Factors <a class="header-anchor" href="#ram-performance-factors" aria-label="Permalink to &quot;RAM Performance Factors&quot;">​</a></h2><ul><li>Generation (DDR3 &lt; DDR4 &lt; DDR5)</li><li>Amount (GB) — more = less swapping to disk</li><li>Clock speed (MHz)</li></ul><hr><h2 id="storage-comparison" tabindex="-1">Storage Comparison <a class="header-anchor" href="#storage-comparison" aria-label="Permalink to &quot;Storage Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>HDD</th><th>SSD</th></tr></thead><tbody><tr><td>Technology</td><td>Spinning magnetic platters</td><td>Flash memory</td></tr><tr><td>Speed</td><td>~100–160 MB/s</td><td>500 MB/s–7 GB/s</td></tr><tr><td>Noise</td><td>Audible</td><td>Silent</td></tr><tr><td>Shock resistant</td><td>Low</td><td>High</td></tr><tr><td>Price/GB</td><td>Cheaper</td><td>More expensive</td></tr><tr><td>Best for</td><td>Bulk/archival storage</td><td>OS, apps, active work</td></tr></tbody></table><hr><h2 id="three-bus-types" tabindex="-1">Three Bus Types <a class="header-anchor" href="#three-bus-types" aria-label="Permalink to &quot;Three Bus Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Bus</th><th>Direction</th><th>Carries</th></tr></thead><tbody><tr><td><strong>Data bus</strong></td><td>Bidirectional</td><td>Actual data</td></tr><tr><td><strong>Address bus</strong></td><td>CPU → memory</td><td>Memory addresses</td></tr><tr><td><strong>Control bus</strong></td><td>Bidirectional</td><td>Control signals (read, write, clock)</td></tr></tbody></table><p>Bus width = number of lines = how many bits in parallel. Wider bus = more data per transfer.</p><hr><h2 id="software-classification" tabindex="-1">Software Classification <a class="header-anchor" href="#software-classification" aria-label="Permalink to &quot;Software Classification&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SOFTWARE</span></span>
<span class="line"><span>├── System Software</span></span>
<span class="line"><span>│   ├── Operating System (process, memory, file, device, security management)</span></span>
<span class="line"><span>│   ├── Utility (antivirus, firewall, backup, disk cleanup, compression)</span></span>
<span class="line"><span>│   └── Device Drivers</span></span>
<span class="line"><span>└── Application Software</span></span>
<span class="line"><span>    ├── General purpose (Word, Excel, Chrome)</span></span>
<span class="line"><span>    ├── Specific purpose (Photoshop, AutoCAD)</span></span>
<span class="line"><span>    └── Custom-written (bespoke for one organisation)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><hr><h2 id="os-types" tabindex="-1">OS Types <a class="header-anchor" href="#os-types" aria-label="Permalink to &quot;OS Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td>GUI</td><td>Graphical, mouse-driven</td><td>Windows, macOS</td></tr><tr><td>CLI</td><td>Text commands</td><td>Linux terminal</td></tr><tr><td>Multi-user</td><td>Many users simultaneously</td><td>Linux server</td></tr><tr><td>Real-time (RTOS)</td><td>Instant response</td><td>Medical device OS</td></tr><tr><td>Embedded</td><td>Dedicated device</td><td>Smart TV OS</td></tr><tr><td>Mobile</td><td>Touchscreen portable</td><td>Android, iOS</td></tr><tr><td>Network OS</td><td>Manages network resources</td><td>Windows Server</td></tr></tbody></table><hr><h2 id="types-of-computers" tabindex="-1">Types of Computers <a class="header-anchor" href="#types-of-computers" aria-label="Permalink to &quot;Types of Computers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Portable?</th><th>Users</th><th>Use</th></tr></thead><tbody><tr><td>Desktop</td><td>✗</td><td>1</td><td>Office/home productivity</td></tr><tr><td>Laptop</td><td>✓</td><td>1</td><td>Mobile personal use</td></tr><tr><td>Tablet</td><td>✓</td><td>1</td><td>Media, education</td></tr><tr><td>Smartphone</td><td>✓</td><td>1</td><td>Communication, apps</td></tr><tr><td>Server</td><td>✗</td><td>Many</td><td>Network services</td></tr><tr><td>Mainframe</td><td>✗</td><td>Thousands</td><td>Mass transactions</td></tr><tr><td>Supercomputer</td><td>✗</td><td>Many</td><td>Scientific simulation</td></tr><tr><td>Embedded</td><td>Varies</td><td>0 (invisible)</td><td>Single dedicated task</td></tr></tbody></table><hr><h2 id="user-type-recommendations" tabindex="-1">User Type Recommendations <a class="header-anchor" href="#user-type-recommendations" aria-label="Permalink to &quot;User Type Recommendations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>User</th><th>CPU</th><th>RAM</th><th>Storage</th><th>GPU</th></tr></thead><tbody><tr><td>Home</td><td>Entry (i3/Ryzen 3)</td><td>8 GB</td><td>Mid SSD</td><td>Integrated</td></tr><tr><td>SOHO</td><td>Mid (i5/Ryzen 5)</td><td>16 GB</td><td>SSD</td><td>Integrated</td></tr><tr><td>Gamer</td><td>High (i7-9/Ryzen 7-9)</td><td>16–32 GB DDR5</td><td>Fast NVMe SSD</td><td>High-end dedicated</td></tr><tr><td>Power user</td><td>Many-core (i9/Threadripper)</td><td>32–64 GB</td><td>Large NVMe SSD</td><td>High-end</td></tr></tbody></table><hr><h2 id="licence-types" tabindex="-1">Licence Types <a class="header-anchor" href="#licence-types" aria-label="Permalink to &quot;Licence Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Free?</th><th>Source?</th><th>Copy?</th></tr></thead><tbody><tr><td>Proprietary</td><td>Paid</td><td>Closed</td><td>No</td></tr><tr><td>Freeware</td><td>Yes</td><td>Closed</td><td>Usually yes</td></tr><tr><td>Shareware</td><td>Trial</td><td>Closed</td><td>Trial only</td></tr><tr><td>Open source</td><td>Usually</td><td>Open</td><td>Yes (under conditions)</td></tr><tr><td>Public domain</td><td>Yes</td><td>Open</td><td>Yes, no restrictions</td></tr></tbody></table><hr><h2 id="data-sizes" tabindex="-1">Data Sizes <a class="header-anchor" href="#data-sizes" aria-label="Permalink to &quot;Data Sizes&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>8 bits = 1 byte</span></span>
<span class="line"><span>1 024 bytes = 1 KB</span></span>
<span class="line"><span>1 024 KB = 1 MB</span></span>
<span class="line"><span>1 024 MB = 1 GB</span></span>
<span class="line"><span>1 024 GB = 1 TB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>Storage calculation:</strong></p><ul><li>Text: characters × 1 byte</li><li>Image: width × height × colour_depth_bits ÷ 8</li><li>Audio: sample_rate × bit_depth × channels × seconds ÷ 8</li></ul>`,49)])])}const u=e(s,[["render",n]]);export{m as __pageData,u as default};
